/// <summary>
/// Extension of the <c>PurchAgreementHeaderHistory</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(PurchAgreementHeaderHistory))]
public final class PurchAgreementHeaderHistoryETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromPurchAgreementHeader</c> method.
/// </summary>
/// <param name="_purchHeader">PurchAgreementHeader.</param>
public void initFromPurchAgreementHeader(PurchAgreementHeader _purchHeader)
{
    next initFromPurchAgreementHeader(_purchHeader);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
    AgreementLine               agreementLine;
    ETGSPAINPurchUnloadPortTable     ETGSPAINPurchUnloadPortTable;
    ETGSPAINPurchLoadPortTable       ETGSPAINPurchLoadPortTable;
    HcmWorker                   HcmWorker = HcmWorker::find(_purchHeader.PrimaryResponsibleWorker);

    this.ETGSPAINCreationDate                        = DateTimeUtil::date(_purchHeader.CreatedDateTime);
    this.ETGSPAINPurchExecutionDueDate               = _purchHeader.ETGSPAINPurchExecutionDueDate;
    this.ETGSPAINPurchExecutionFromDate              = _purchHeader.ETGSPAINPurchExecutionFromDate;
    this.ETGSPAINSalesVendGroup                      = _purchHeader.vendTable().VendGroup;
    this.ETGSPAINPurchPlateDaysNumber                = _purchHeader.ETGSPAINPurchPlateDaysNumber;
    this.ETGSPAINDefaultAgreementLineEffectiveDate   = _purchHeader.DefaultAgreementLineEffectiveDate;        

    select firstonly agreementLine
        order by ETGSPAINPurchLoadPortId desc
        where agreementLine.Agreement                       == _purchHeader.RecId
            outer join ETGSPAINPurchLoadPortTable
                where ETGSPAINPurchLoadPortTable.LoadPortId      == agreementLine.ETGSPAINPurchLoadPortId;

    this.ETGSPAINLoadCity                            = ETGSPAINPurchLoadPortTable.AdressCity;

    select firstonly agreementLine
        order by ETGSPAINPurchUnloadPortId desc
        where agreementLine.Agreement                       == _purchHeader.RecId
            outer join ETGSPAINPurchUnloadPortTable
                where ETGSPAINPurchUnloadPortTable.UnloadPortId  == agreementLine.ETGSPAINPurchUnloadPortId;

    this.ETGSPAINUnloadCity                          = ETGSPAINPurchUnloadPortTable.AdressCity; 

    this.ETGSPAINPurchIntermediary                   = HcmWorker.name();                
    }
}
